def _ms_to_utc(value):
    if not value:
        return ''
    try:
        return datetime.datetime.fromtimestamp(int(value) / 1000, datetime.timezone.utc)
    except (ValueError, OverflowError, OSError, TypeError):
        return ''


@artifact_processor
def get_googleLastTrip(files_found, report_folder, seeker, wrap_text):
    data_list = []
    source_path = ''
    for file_found in files_found:
        file_found = str(file_found)
        source_path = file_found
        try:
            with open(file_found, 'rb') as f:
                data = f.read()
            values, _ = blackboxprotobuf.decode_message(data[8:], TYPEDEF)
        except Exception:
            continue

        timeofstart = ''
        timeofstop = ''
        startloc = ''
        destination = ''
        latyour = ''
        longyour = ''
        latdest = ''
        longdest = ''
        destdata = ''
        for key, value in values.items():
            try:
                if key == '2':
                    for entry in value.items():
                        startinfo = entry[1]['1']['1']['1']['1']
                        latyour = startinfo['3']['3']
                        longyour = startinfo['3']['4']
                        if '4' in startinfo:
                            startloc = startinfo['4'].decode()
                        if '1' in startinfo:
                            startloc = startinfo['1'].decode()
                        destinfo = entry[1]['1']['1-1']['1']['1']
                        latdest = destinfo['3']['3']
                        longdest = destinfo['3']['4']
                        if '4' in destinfo:
                            destination = destinfo['4'].decode()
                        if '1' in destinfo:
                            destination = destinfo['1'].decode()
                        destdata = entry[1]['1']['12'].decode()
                elif key == '4':
                    timeofstop = _ms_to_utc(value)
                elif key == '5':
                    timeofstart = _ms_to_utc(value['1'])
            except (KeyError, TypeError, AttributeError, IndexError):
                continue

        if timeofstart or timeofstop or startloc or destination:
            data_list.append((timeofstart, 'Start', startloc, latyour, longyour, destdata))
            data_list.append((timeofstop, 'End', destination, latdest, longdest, ''))

    data_headers = (('Timestamp', 'datetime'), 'Directionality', 'Place', 'Latitude', 'Longitude', 'Data')
    return data_headers, data_list, source_path
